const reviews = $input.first().json.reviews || [];
const unanswered = reviews.filter(function(r) { return !r.reviewReply || !r.reviewReply.comment; });
const toProcess = unanswered.slice(0, 5);
return [{ json: { count: toProcess.length, reviews: toProcess } }];

var data = $input.first().json;
var reviews = data.reviews;
var reviewsText = '';
for (var i = 0; i < reviews.length; i++) {
  var r = reviews[i];
  var author = (r.reviewer && r.reviewer.displayName) ? r.reviewer.displayName : 'Anonimo';
  var comment = r.comment || 'nessun commento';
  var stars = r.starRating || 'ND';
  reviewsText += '### RECENSIONE ' + (i+1) + ' | Autore: ' + author + ' | Stelle: ' + stars + ' | Commento: ' + comment + ' ';
}
var prompt = 'Sei il community manager di una PMI italiana. ';
prompt += 'Genera risposte professionali in italiano per le seguenti recensioni Google. ';
prompt += 'Voto 4-5 stelle: risposta calorosa e personalizzata, cita dettagli del commento, invita a tornare. ';
prompt += 'Voto 1-3 stelle: empatia, scuse sincere, offerta di risolvere offline contattandoci, mai difensivo. ';
prompt += 'Rispondi SOLO con un JSON array valido. Ogni elemento ha i campi indice (numero) e risposta (stringa). ';
prompt += 'Recensioni da processare: ' + reviewsText;
return [{ json: { prompt: prompt, count: reviews.length, reviews: reviews } }];

var claudeRaw = $input.first().json.content[0].text;
var reviews = $('Prepara Prompt Claude').first().json.reviews;
var risposte = [];
try {
  var txt = claudeRaw.trim();
  var start = txt.indexOf('[');
  var end = txt.lastIndexOf(']');
  if (start !== -1 && end !== -1) { txt = txt.substring(start, end + 1); }
  risposte = JSON.parse(txt);
} catch(e) {
  risposte = [{ indice: 1, risposta: claudeRaw }];
}
var result = [];
for (var i = 0; i < risposte.length; i++) {
  var r = risposte[i];
  var review = reviews[i] || {};
  result.push({
    indice: r.indice || i + 1,
    autore: (review.reviewer && review.reviewer.displayName) ? review.reviewer.displayName : 'Anonimo',
    voto: review.starRating || 'ND',
    commento: review.comment || 'nessun commento',
    bozza_risposta: r.risposta || ''
  });
}
return [{ json: { risposte: result, count: result.length } }];

var data = $input.first().json;
var risposte = data.risposte;
var today = new Date().toLocaleDateString('it-IT');
var html = '<html><body>';
html += '<h2>Recensioni Google da rispondere - ' + today + '</h2>';
html += '<p>Hai <strong>' + risposte.length + '</strong> nuova/e recensione/i senza risposta. Copia la bozza e incollala su Google Business Profile.</p>';
for (var i = 0; i < risposte.length; i++) {
  var r = risposte[i];
  var tipo = (r.voto === 'FOUR' || r.voto === 'FIVE') ? 'POSITIVA' : 'NEGATIVA';
  html += '<hr>';
  html += '<h3>Recensione ' + r.indice + ' - ' + tipo + ' - ' + r.voto + ' stelle - ' + r.autore + '</h3>';
  html += '<p><strong>Commento del cliente:</strong> ' + r.commento + '</p>';
  html += '<p><strong>Bozza risposta generata da Claude:</strong></p>';
  html += '<blockquote>' + r.bozza_risposta + '</blockquote>';
}
html += '<hr><p><small>Generato da n8n Automation Pack Italia - Workflow 05</small></p>';
html += '</body></html>';
var subject = 'Recensioni Google da rispondere (' + risposte.length + ') - ' + today;
return [{ json: { html: html, subject: subject } }];
